local BabyBox = Tabs.Main:AddRightGroupbox("幼龙")
local StatsBox = Tabs.Main:AddRightGroupbox("统计数据")

local growthLabel = StatsBox:AddLabel("Growth : 0")
local rankLabel = StatsBox:AddLabel("Rank : #0")

task.spawn(function()
	while task.wait(0.5) do
		Module.updateStats(growthLabel, rankLabel)
		if Library.Unloaded then break end
	end
end)

FarmBox:AddDropdown("TargetType", {
	Values = {"All", "Eggs", "Meats", "Nests"},
	Default = 1,
	Text = "Target",
	Callback = function(Value)
		Module.targetType = Value
	end,
})

FarmBox:AddToggle("FarmToggle", {
	Text = "自动农场",
	Default = false,
	Callback = function(Value)
		Module.farmActive = Value
		if not Value then
			if Module.lockCamera then
				Module.camera.CameraType = Enum.CameraType.Custom
				Module.cameraCFrame = nil
			end
		end
	end,
})

FarmBox:AddToggle("LockCamera", {
	Text = "锁定视角",
	Default = false,
	Callback = function(Value)
		Module.lockCamera = Value
		if not Value then
			Module.camera.CameraType = Enum.CameraType.Custom
			Module.cameraCFrame = nil
		end
	end,
})

