	Text = "狩猎弱小玩家",
	Default = false,
	Callback = function(Value)
		Module.huntActive = Value
	end,
})

BabyBox:AddToggle("BabyToggle", {
	Text = "自动收集幼崽",
	Default = false,
	Callback = function(Value)
		Module.babyDinoActive = Value
	end,
})

MoveBox:AddToggle("Flight", {
	Text = "视角飞行",
